static inline void dot_prod(int8_t * sptr, const int8_t * kptr, uint32_t size, int32_t * result)
{
	int32_t sum = 0;
	uint32_t i = 0, cnt = (size >> 3) << 3;
	for(; i + 8 - 1 < cnt;)
	{
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
		sum += sptr[i] * kptr[i]; i++;
	}
	for(; i < size; i++)
		sum += sptr[i] * kptr[i];
	*result = sum;
}

static inline void dot_prod_pack2(int8_t * sptr, const int8_t * kptr, uint32_t size, int32_t * result)
{
	int32_t s0 = 0, s1 = 0;
	const int8_t * k0 = kptr, * k1 = kptr + size;
	uint32_t i = 0, cnt = (size >> 3) << 3;
	for(; i + 8 - 1 < cnt;)
	{
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
		s0 += sptr[i] * k0[i]; s1 += sptr[i] * k1[i]; i++;
	}
	for(; i < size; i++)
	{
		s0 += sptr[i] * k0[i];
		s1 += sptr[i] * k1[i];
	}
	result[0] = s0;
	result[1] = s1;
}

static inline void dot_prod_3x3x1(int8_t * sptr, const int8_t * kptr, int32_t * result)
{
	*result = sptr[0] * kptr[0] + sptr[1] * kptr[1] + sptr[2] * kptr[2]
	        + sptr[3] * kptr[3] + sptr[4] * kptr[4] + sptr[5] * kptr[5]
	        + sptr[6] * kptr[6] + sptr[7] * kptr[7] + sptr[8] * kptr[8];
}

static inline void postprocess(int n, int32_t * s, const int32_t * b, int8_t * outp, const int32_t * sw_i, int32_t thresh_i)
{
	for(int i = 0; i < n; i++)
	{
		int64_t v = (int64_t)(s[i] + b[i]) * sw_i[i];
		v >>= 31;
		if(v < 0) v = 0;
		if(v > thresh_i) v = thresh_i;
		outp[i] = (int8_t)(v - 128);
	}
}


