struct vww_pdat_t {
	uint8_t img[27648];
	int8_t a[18432];
	int8_t b[36864];
};

static int vww_detect(struct vww_pdat_t * pdat)
{
	// L0: CONV2D 96x96x3 -> 48x48x8
	l0(pdat->img, pdat->b);
	// L1: DWCONV2D 48x48x8 -> 48x48x8
	l1(pdat->b, pdat->a);
	// L2: CONV2D 48x48x8 -> 48x48x16
	l2(pdat->a, pdat->b);
	// L3: DWCONV2D 48x48x16 -> 24x24x16
	l3(pdat->b, pdat->a);
	// L4: CONV2D 24x24x16 -> 24x24x32
	l4(pdat->a, pdat->b);
	// L5: DWCONV2D 24x24x32 -> 24x24x32
	l5(pdat->b, pdat->a);
	// L6: CONV2D 24x24x32 -> 24x24x32
	l6(pdat->a, pdat->b);
	// L7: DWCONV2D 24x24x32 -> 12x12x32
	l7(pdat->b, pdat->a);
	// L8: CONV2D 12x12x32 -> 12x12x64
	l8(pdat->a, pdat->b);
	// L9: DWCONV2D 12x12x64 -> 12x12x64
	l9(pdat->b, pdat->a);
	// L10: CONV2D 12x12x64 -> 12x12x64
	l10(pdat->a, pdat->b);
	// L11: DWCONV2D 12x12x64 -> 6x6x64
	l11(pdat->b, pdat->a);
	// L12: CONV2D 6x6x64 -> 6x6x128
	l12(pdat->a, pdat->b);
	// L13: DWCONV2D 6x6x128 -> 6x6x128
	l13(pdat->b, pdat->a);
	// L14: CONV2D 6x6x128 -> 6x6x128
	l14(pdat->a, pdat->b);
	// L15: DWCONV2D 6x6x128 -> 6x6x128
	l15(pdat->b, pdat->a);
	// L16: CONV2D 6x6x128 -> 6x6x128
	l16(pdat->a, pdat->b);
	// L17: DWCONV2D 6x6x128 -> 6x6x128
	l17(pdat->b, pdat->a);
	// L18: CONV2D 6x6x128 -> 6x6x128
	l18(pdat->a, pdat->b);
	// L19: DWCONV2D 6x6x128 -> 6x6x128
	l19(pdat->b, pdat->a);
	// L20: CONV2D 6x6x128 -> 6x6x128
	l20(pdat->a, pdat->b);
	// L21: DWCONV2D 6x6x128 -> 6x6x128
	l21(pdat->b, pdat->a);
	// L22: CONV2D 6x6x128 -> 6x6x128
	l22(pdat->a, pdat->b);
	// L23: DWCONV2D 6x6x128 -> 3x3x128
	l23(pdat->b, pdat->a);
	// L24: CONV2D 3x3x128 -> 3x3x256
	l24(pdat->a, pdat->b);
	// L25: DWCONV2D 3x3x256 -> 3x3x256
	l25(pdat->b, pdat->a);
	// L26: CONV2D 3x3x256 -> 3x3x256
	l26(pdat->a, pdat->b);
	// L27: CONV2D 3x3x256 -> 3x3x2
	l27(pdat->b, pdat->a);
	// L28: GAP 3x3x2 -> 1x1x2
	l28(pdat->a, pdat->b);
	// L29: SOFTMAX 2 classes
	return (int)sigmoid_lut[((int)pdat->b[0] - (int)pdat->b[1]) + 255];
}

static void vww_prepare(struct vision_t * v, uint8_t * img)
{
	int vw = v->width;
	int vh = v->height;
	int scale = XMIN(vw, vh);
	int crop_w = vw * 96 / scale;
	int crop_h = vh * 96 / scale;
	int cx = (vw - crop_w) / 2;
	int cy = (vh - crop_h) / 2;

	switch(v->type)
	{
	case VISION_TYPE_GRAY:
		{
			unsigned char * gray = (unsigned char *)v->datas;

			for(int y = 0; y < 96; y++)
			{
				unsigned char * src_row = gray + (cy + y * crop_h / 96) * vw;
				uint8_t * dst = img + y * 288;
				for(int x = 0; x < 96; x++)
				{
					uint8_t val = src_row[cx + x * crop_w / 96];
					*dst++ = val;
					*dst++ = val;
					*dst++ = val;
				}
			}
		}
		break;
	case VISION_TYPE_RGB:
		{
			unsigned char * r = &((unsigned char *)v->datas)[v->npixel * 0];
			unsigned char * g = &((unsigned char *)v->datas)[v->npixel * 1];
			unsigned char * b = &((unsigned char *)v->datas)[v->npixel * 2];

			for(int y = 0; y < 96; y++)
			{
				int src_off = (cy + y * crop_h / 96) * vw;
				uint8_t * dst = img + y * 288;
				for(int x = 0; x < 96; x++)
				{
					int idx = src_off + cx + x * crop_w / 96;
					*dst++ = r[idx];
					*dst++ = g[idx];
					*dst++ = b[idx];
				}
			}
		}
		break;
	default:
		break;
	}
}

int vision_vww(struct vision_t * v)
{
	if(v)
	{
		struct vww_pdat_t * pdat = xos_mem_malloc(sizeof(struct vww_pdat_t));
		if(pdat)
		{
			vww_prepare(v, pdat->img);
			int percent = vww_detect(pdat);
			xos_mem_free(pdat);
			return percent;
		}
	}
	return 0;
}
